  1→//! Mock value space selection and live-first fallback logic.
  2→//!
  3→//! When Shatter encounters an external dependency during exploration, it must
  4→//! decide how to provide return values. [`MockValueSpace`] captures the
  5→//! available strategies; [`LiveFirstState`] implements a state machine that
  6→//! attempts live calls first and falls back to synthetic mocks on connection
  7→//! failure.
  8→
  9→use serde::{Deserialize, Serialize};
 10→
 11→// ---------------------------------------------------------------------------
 12→// MockValueSpace — strategy for generating mock return values
 13→// ---------------------------------------------------------------------------
 14→
 15→/// Strategy for selecting mock return values during exploration.
 16→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 17→#[serde(rename_all = "snake_case", tag = "kind")]
 18→pub enum MockValueSpace {
 19→    /// Try the real service first; fall back to synthetic mocks on connection
 20→    /// failure. This is the default for network/database dependencies.
 21→    LiveFirst,
 22→    /// Use a fixed set of user-provided return values (round-robin).
 23→    FixedSet { values: Vec<serde_json::Value> },
 24→    /// Engine generates values autonomously based on type information.
 25→    Autonomous,
 26→    /// Replay a recorded seed corpus (e.g. from a prior live session).
 27→    Seeded { seed_file: String },
 28→}
 29→
 30→// ---------------------------------------------------------------------------
 31→// Live call outcome classification
 32→// ---------------------------------------------------------------------------
 33→
 34→/// Coarse classification of a live call attempt.
 35→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 36→#[serde(rename_all = "snake_case", tag = "outcome")]
 37→pub enum LiveCallOutcome {
 38→    /// Call succeeded — the return value is usable.
 39→    Success,
 40→    /// Infrastructure-level failure — the service is unreachable.
 41→    ConnectionFailure { kind: ConnectionFailureKind },
 42→    /// Application-level error (e.g. HTTP 4xx/5xx) — service is reachable but
 43→    /// returned an error. Still useful as an observed behavior.
 44→    AppError { message: String },
 45→}
 46→
 47→/// Subcategories of connection failure, used for diagnostics and to decide
 48→/// whether retries are worthwhile.
 49→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 50→#[serde(rename_all = "snake_case")]
 51→pub enum ConnectionFailureKind {
 52→    ConnectionRefused,
 53→    DnsFailure,
 54→    AuthError,
 55→    Timeout,
 56→    Other,
 57→}
 58→
 59→// ---------------------------------------------------------------------------
 60→// Error heuristic patterns — named constants for substring matching
 61→// ---------------------------------------------------------------------------
 62→
 63→/// Patterns indicating a refused TCP connection.
 64→pub const CONN_REFUSED_PATTERNS: &[&str] = &["ECONNREFUSED", "connection refused", "Connection refused"];
 65→
 66→/// Patterns indicating a DNS resolution failure.
 67→pub const DNS_FAILURE_PATTERNS: &[&str] = &[
 68→    "ENOTFOUND",
 69→    "EAI_AGAIN",
 70→    "dns resolution",
 71→    "DNS resolution",
 72→    "getaddrinfo",
 73→    "no such host",
 74→];
 75→
 76→/// Patterns indicating an authentication/authorization failure.
 77→pub const AUTH_ERROR_PATTERNS: &[&str] = &[
 78→    "EAUTH",
 79→    "authentication failed",
 80→    "unauthorized",
 81→    "403 Forbidden",
 82→    "401 Unauthorized",
 83→    "invalid credentials",
 84→];
 85→
 86→/// Patterns indicating a timeout.
 87→pub const TIMEOUT_PATTERNS: &[&str] = &[
 88→    "ETIMEDOUT",
 89→    "ESOCKETTIMEDOUT",
 90→    "ETIME",
 91→    "timed out",
 92→    "timeout",
 93→    "deadline exceeded",
 94→];
 95→
 96→/// HTTP status codes that indicate application-level errors (not infra).
 97→pub const APP_ERROR_STATUS_CODES: &[&str] = &["400 ", "404 ", "409 ", "422 ", "500 ", "502 ", "503 "];
 98→
 99→// ---------------------------------------------------------------------------
100→// Classification functions
101→// ---------------------------------------------------------------------------
102→
103→/// Classify an error message as a specific connection failure kind.
104→///
105→/// Returns `None` if the message doesn't match any known connection failure
106→/// pattern (it may be an application error or unknown failure).
107→pub fn classify_connection_failure(error_msg: &str) -> Option<ConnectionFailureKind> {
108→    if CONN_REFUSED_PATTERNS.iter().any(|p| error_msg.contains(p)) {
109→        return Some(ConnectionFailureKind::ConnectionRefused);
110→    }
111→    if DNS_FAILURE_PATTERNS.iter().any(|p| error_msg.contains(p)) {
112→        return Some(ConnectionFailureKind::DnsFailure);
113→    }
114→    if AUTH_ERROR_PATTERNS.iter().any(|p| error_msg.contains(p)) {
115→        return Some(ConnectionFailureKind::AuthError);
116→    }
117→    if TIMEOUT_PATTERNS.iter().any(|p| error_msg.contains(p)) {
118→        return Some(ConnectionFailureKind::Timeout);
119→    }
120→    None
121→}
122→
123→/// Classify the result of a live call attempt.
124→///
125→/// - `Ok(value)` → [`LiveCallOutcome::Success`]
126→/// - `Err(msg)` where msg matches a connection pattern → [`LiveCallOutcome::ConnectionFailure`]
127→/// - `Err(msg)` otherwise → [`LiveCallOutcome::AppError`]
128→pub fn classify_live_call(result: &Result<serde_json::Value, String>) -> LiveCallOutcome {
129→    match result {
130→        Ok(_) => LiveCallOutcome::Success,
131→        Err(msg) => match classify_connection_failure(msg) {
132→            Some(kind) => LiveCallOutcome::ConnectionFailure { kind },
133→            None => LiveCallOutcome::AppError {
134→                message: msg.clone(),
135→            },
136→        },
137→    }
138→}
139→
140→// ---------------------------------------------------------------------------
141→// LiveFirstState — state machine for live-first fallback
142→// ---------------------------------------------------------------------------
143→
144→/// State machine tracking whether a live service is available.
145→///
146→/// Transitions:
147→/// - `Untried` + `Success`           → `Available`
148→/// - `Untried` + `ConnectionFailure` → `Unavailable`
149→/// - `Untried` + `AppError`          → `Available` (service is reachable)
150→/// - `Available` + `ConnectionFailure` → `Unavailable`
151→/// - `Available` + `Success`/`AppError` → `Available`
152→/// - `Unavailable` is terminal (no retries within a single exploration run)
153→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Hash, Serialize, Deserialize)]
154→#[serde(rename_all = "snake_case")]
155→pub enum LiveFirstState {
156→    /// Haven't tried calling the service yet.
157→    #[default]
158→    Untried,
159→    /// At least one successful contact — keep using live calls.
160→    Available,
161→    /// Connection failure observed — fall back to synthetic mocks for the
162→    /// remainder of this exploration run.
163→    Unavailable,
164→}
165→
166→impl LiveFirstState {
167→    /// Advance the state machine based on a call outcome.
168→    pub fn transition(self, outcome: &LiveCallOutcome) -> Self {
169→        match (self, outcome) {
170→            // Terminal state — no recovery within a run.
171→            (Self::Unavailable, _) => Self::Unavailable,
172→
173→            // Connection failure from any non-terminal state → unavailable.
174→            (_, LiveCallOutcome::ConnectionFailure { .. }) => Self::Unavailable,
175→
176→            // Success or app error from untried/available → available.
177→            (Self::Untried | Self::Available, LiveCallOutcome::Success | LiveCallOutcome::AppError { .. }) => {
178→                Self::Available
179→            }
180→        }
181→    }
182→
183→    /// Whether we should attempt a live call in this state.
184→    pub fn should_try_live(self) -> bool {
185→        matches!(self, Self::Untried | Self::Available)
186→    }
187→}
188→
