200→    #[test]
201→    fn mock_value_space_serde_roundtrip() {
202→        let variants = vec![
203→            MockValueSpace::LiveFirst,
204→            MockValueSpace::FixedSet {
205→                values: vec![json!(1), json!("hello"), json!(null)],
206→            },
