419→    // -- Proptest --
420→
421→    mod proptests {
422→        use super::super::*;
423→        use proptest::prelude::*;
424→        use serde_json::json;
425→
426→        fn arb_mock_value_space() -> impl Strategy<Value = MockValueSpace> {
427→            prop_oneof![
428→                Just(MockValueSpace::LiveFirst),
429→                prop::collection::vec(
430→                    prop_oneof![
431→                        Just(json!(null)),
432→                        Just(json!(42)),
433→                        Just(json!("test")),
434→                        Just(json!(true)),
435→                    ],
436→                    0..5,
437→                )
438→                .prop_map(|values| MockValueSpace::FixedSet { values }),
439→                Just(MockValueSpace::Autonomous),
440→                "[a-z/_]{1,30}".prop_map(|seed_file| MockValueSpace::Seeded { seed_file }),
441→            ]
442→        }
443→
444→        fn arb_connection_failure_kind() -> impl Strategy<Value = ConnectionFailureKind> {
445→            prop_oneof![
446→                Just(ConnectionFailureKind::ConnectionRefused),
447→                Just(ConnectionFailureKind::DnsFailure),
448→                Just(ConnectionFailureKind::AuthError),
449→                Just(ConnectionFailureKind::Timeout),
450→                Just(ConnectionFailureKind::Other),
451→            ]
452→        }
453→
454→        fn arb_live_call_outcome() -> impl Strategy<Value = LiveCallOutcome> {
455→            prop_oneof![
456→                Just(LiveCallOutcome::Success),
457→                arb_connection_failure_kind()
458→                    .prop_map(|kind| LiveCallOutcome::ConnectionFailure { kind }),
459→                ".{0,50}".prop_map(|message| LiveCallOutcome::AppError { message }),
460→            ]
461→        }
462→
463→        fn arb_live_first_state() -> impl Strategy<Value = LiveFirstState> {
464→            prop_oneof![
465→                Just(LiveFirstState::Untried),
466→                Just(LiveFirstState::Available),
467→                Just(LiveFirstState::Unavailable),
468→            ]
469→        }
470→
471→        proptest! {
472→            #[test]
473→            fn mock_value_space_roundtrip(mvs in arb_mock_value_space()) {
474→                let json = serde_json::to_string(&mvs).unwrap();
475→                let back: MockValueSpace = serde_json::from_str(&json).unwrap();
476→                prop_assert_eq!(&back, &mvs);
477→            }
478→
479→            #[test]
480→            fn live_call_outcome_roundtrip(outcome in arb_live_call_outcome()) {
481→                let json = serde_json::to_string(&outcome).unwrap();
482→                let back: LiveCallOutcome = serde_json::from_str(&json).unwrap();
483→                prop_assert_eq!(&back, &outcome);
484→            }
485→
486→            #[test]
487→            fn live_first_state_roundtrip(state in arb_live_first_state()) {
488→                let json = serde_json::to_string(&state).unwrap();
489→                let back: LiveFirstState = serde_json::from_str(&json).unwrap();
490→                prop_assert_eq!(&back, &state);
491→            }
492→
493→            // Unavailable is terminal: no outcome can leave it.
494→            #[test]
495→            fn unavailable_is_terminal(outcome in arb_live_call_outcome()) {
496→                prop_assert_eq!(
497→                    LiveFirstState::Unavailable.transition(&outcome),
498→                    LiveFirstState::Unavailable
499→                );
500→            }
501→
502→            // Connection failure always leads to Unavailable (from any non-terminal state).
503→            #[test]
504→            fn conn_failure_always_unavailable(
505→                state in arb_live_first_state(),
506→                kind in arb_connection_failure_kind(),
507→            ) {
508→                let next = state.transition(&LiveCallOutcome::ConnectionFailure { kind });
509→                prop_assert_eq!(next, LiveFirstState::Unavailable);
510→            }
511→
512→            // Success from a non-Unavailable state always leads to Available.
513→            #[test]
514→            fn success_leads_to_available(state in arb_live_first_state()) {
515→                if state != LiveFirstState::Unavailable {
516→                    prop_assert_eq!(
517→                        state.transition(&LiveCallOutcome::Success),
518→                        LiveFirstState::Available
519→                    );
520→                }
521→            }
522→
523→            // should_try_live is false iff state is Unavailable.
524→            #[test]
525→            fn should_try_live_iff_not_unavailable(state in arb_live_first_state()) {
526→                prop_assert_eq!(
527→                    state.should_try_live(),
528→                    state != LiveFirstState::Unavailable
529→                );
530→            }
531→
532→            // classify_live_call(Ok(_)) is always Success.
533→            #[test]
534→            fn classify_ok_is_success(_v in prop_oneof![Just(json!(1)), Just(json!("x"))]) {
535→                let outcome = classify_live_call(&Ok(_v));
536→                prop_assert_eq!(outcome, LiveCallOutcome::Success);
537→            }
538→        }
539→    }
540→}
